import React, { useState } from "react";
import { fetchAppointmentsByPatient } from "../utils/api";
import "./AppointmentList.css";

export default function AppointmentList() {
  const [patientId, setPatientId] = useState("");
  const [appointments, setAppointments] = useState([]);

  const handleChange = async (e) => {
    const value = e.target.value;
    setPatientId(value);
    try {
      const data = await fetchAppointmentsByPatient(value);
      setAppointments(data || []);
    } catch {
      setAppointments([]);
    }
  };

  return (
    <div>
      <select
        data-testid="patient-filter"
        value={patientId}
        onChange={handleChange}
      >
        <option value="">Select patient</option>
        <option value="1">Patient 1</option>
        <option value="2">Patient 2</option>
      </select>

      {appointments.length === 0 ? (
        <div data-testid="no-appointments">No appointments</div>
      ) : (
        <ul>
          {appointments.map((a) => (
            <li key={a.id}>
              {a.reason} - {a.appointmentDate} {a.appointmentTime}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
